class AuthNotifier extends ChangeNotifier {
  final AuthManager _authManager = AuthManager();
  bool _isInitialized = false;

  bool get isInitialized => _isInitialized;
  bool get isLoggedIn => _authManager.isLoggedIn;
  User? get currentUser => _authManager.currentUser;
  String? get accessToken => _authManager.accessToken;

  Future<void> initialize() async {
    await _authManager.initialize();
    _isInitialized = true;
    notifyListeners();
  }

  Future<bool> login(String email, String password) async {
    final success = await _authManager.login(email, password);
    if (success) {
      notifyListeners();
    }
    return success;
  }

  Future<void> logout() async {
    await _authManager.logout();
    notifyListeners();
  }

  Future<void> updateUser(User user) async {
    await _authManager.updateUserData(user);
    notifyListeners();
  }

  Future<String?> refreshToken() async {
    final token = await _authManager.refreshAccessToken();
    if (token != null) {
      notifyListeners();
    }
    return token;
  }
}

